mapper.select:
SELECT a.wrk_mast_id , b.rsch_cls_cd , (SELECT comm_cd_nm FROM sy_code_dtl WHERE wrk_tp_cd = 'RP' AND cd_tp_cd = '020' AND comm_cd = b.rsch_cls_cd) AS rsch_cls_nm , b.prj_nm , c.rcpt_dt , a.prgrs_stat_cd , (SELECT comm_cd_nm FROM sy_code_dtl WHERE wrk_tp_cd = 'RP' AND cd_tp_cd = '070' AND comm_cd = a.prgrs_stat_cd) AS prgrs_stat_nm , a.opl_wrt_dt , b.rsch_prj_id FROM rp_pre_rview_mst a INNER JOIN rp_rsch_prj_mst b ON a.rsch_prj_id = b.rsch_prj_id AND a.wrk_mast_id = b.wrk_mast_id INNER JOIN rp_prj_rcpt_mst c ON b.wrk_mast_id = c.wrk_mast_id AND b.rsch_prj_id = c.rsch_prj_id WHERE c.prgrs_stat_cd = '020' AND a.use_yn = 'Y' AND a.del_yn = 'N'
AND b.prj_targ_yy = #{P_prj_targ_yy}
AND b.rsch_ctg_cd = #{P_rsch_ctg_cd}
AND b.rsch_cls_cd = #{P_rsch_cls_cd}
AND b.prj_nm LIKE '%' || #{P_prj_nm} || '%'
AND a.prgrs_stat_cd = #{P_prgrs_stat_cd}
AND c.rcpt_dt >= #{P_rcpt_dt_from}
AND c.rcpt_dt <= #{P_rcpt_dt_to}
ORDER BY c.rcpt_dt DESC, b.prj_nm
